import React, { useState, useEffect } from "react";
import {
  getMyTimeSlots,
  createTimeSlot,
  deleteTimeSlot,
} from "../services/bookingService";
import { getMyPlayrooms } from "../services/playroomService";
import { useAuth } from "../context/AuthContext";
import "../styles/ManageTimeSlots.css";

const ManageTimeSlots = () => {
  const { user } = useAuth();
  const [timeSlots, setTimeSlots] = useState([]);
  const [playrooms, setPlayrooms] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    playroomId: "",
    datum: "",
    vremeOd: "10:00",
    vremeDo: "12:00",
    maxDece: 20,
    cena: 800,
  });

  useEffect(() => {
    if (user?.role === "vlasnik" || user?.role === "admin") {
      loadData();
    }
  }, [user]);

  const loadData = async () => {
    setLoading(true);
    const playroomsResult = await getMyPlayrooms();
    if (playroomsResult.success) {
      setPlayrooms(playroomsResult.data);
      if (playroomsResult.data.length > 0) {
        setFormData((prev) => ({
          ...prev,
          playroomId: playroomsResult.data[0]._id,
        }));
      }
    }

    const slotsResult = await getMyTimeSlots();
    if (slotsResult.success) {
      setTimeSlots(slotsResult.data);
    }
    setLoading(false);
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const result = await createTimeSlot(formData);
    if (result.success) {
      setShowForm(false);
      loadData();
    } else {
      alert(result.error);
    }
  };

  const handleDelete = async (id) => {
    if (
      window.confirm("Da li ste sigurni da želite da obrišete ovaj termin?")
    ) {
      const result = await deleteTimeSlot(id);
      if (result.success) {
        loadData();
      } else {
        alert(result.error);
      }
    }
  };

  if (user?.role !== "vlasnik" && user?.role !== "admin") {
    return (
      <div className="container">
        <h1>Pristup zabranjen</h1>
        <p>Samo vlasnici igraonica mogu upravljati terminima.</p>
      </div>
    );
  }

  if (playrooms.length === 0) {
    return (
      <div className="container">
        <h1>Upravljanje terminima</h1>
        <p>Prvo morate dodati igraonicu.</p>
        <button
          className="btn-primary"
          onClick={() => (window.location.href = "/create-playroom")}
        >
          Dodaj igraonicu
        </button>
      </div>
    );
  }

  return (
    <div className="container manage-slots-page">
      <div className="manage-header">
        <h1>Upravljanje terminima</h1>
        <button className="btn-primary" onClick={() => setShowForm(!showForm)}>
          {showForm ? "Zatvori formu" : "+ Dodaj termin"}
        </button>
      </div>

      {showForm && (
        <div className="slot-form">
          <h2>Kreiraj novi termin</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Igraonica</label>
              <select
                name="playroomId"
                value={formData.playroomId}
                onChange={handleChange}
                required
              >
                {playrooms.map((p) => (
                  <option key={p._id} value={p._id}>
                    {p.naziv}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Datum</label>
                <input
                  type="date"
                  name="datum"
                  value={formData.datum}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Od</label>
                <input
                  type="time"
                  name="vremeOd"
                  value={formData.vremeOd}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Do</label>
                <input
                  type="time"
                  name="vremeDo"
                  value={formData.vremeDo}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Maksimalan broj dece</label>
                <input
                  type="number"
                  name="maxDece"
                  value={formData.maxDece}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Cena po detetu (RSD)</label>
                <input
                  type="number"
                  name="cena"
                  value={formData.cena}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <button type="submit" className="btn-success">
              Kreiraj termin
            </button>
          </form>
        </div>
      )}

      <h2>Postojeći termini</h2>
      {timeSlots.length === 0 ? (
        <div className="empty-state">
          <p>
            Još nemate nijedan termin. Kliknite na dugme iznad da dodate prvi
            termin.
          </p>
        </div>
      ) : (
        <div className="slots-list">
          {timeSlots.map((slot) => (
            <div key={slot._id} className="slot-card">
              <div className="slot-info">
                <h3>{slot.playroomId?.naziv}</h3>
                <p>📅 {new Date(slot.datum).toLocaleDateString("sr-RS")}</p>
                <p>
                  ⏰ {slot.vremeOd} - {slot.vremeDo}
                </p>
                <p>
                  👥 Slobodno: {slot.slobodno}/{slot.maxDece}
                </p>
                <p>💰 {slot.cena} RSD/dete</p>
              </div>
              <button
                className="btn-danger"
                onClick={() => handleDelete(slot._id)}
              >
                Obriši
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ManageTimeSlots;
